INSERT INTO t_p83689144_profix_network_admin.shop_products
  (category_id, name, description, price, price_old, sku, in_stock, is_active, image_url, sort_order)
VALUES
  (4, 'Картридж HP 85A (CE285A)', 'Оригинальный лазерный картридж HP 85A для принтеров HP LaserJet Pro P1102, P1102w, M1132, M1212nf. Ресурс — 1600 страниц при 5% заполнении. Обеспечивает высокое качество печати и надёжную работу устройства без потёков и полос.', 3490, 3990, 'CE285A', TRUE, TRUE, 'https://cdn.poehali.dev/projects/16dea1b8-f4a6-4881-9a41-93285e290dcb/files/36328b98-8f3b-4cda-9d43-4b29bb1b5bd1.jpg', 1),
  (4, 'Картридж HP 12A (Q2612A)', 'Оригинальный лазерный картридж HP 12A для принтеров HP LaserJet 1010, 1012, 1015, 1018, 1020, 1022, 3015, 3020, 3030. Ресурс — 2000 страниц при 5% заполнении. Стабильное качество печати на протяжении всего срока службы.', 3190, 3690, 'Q2612A', TRUE, TRUE, 'https://cdn.poehali.dev/projects/16dea1b8-f4a6-4881-9a41-93285e290dcb/files/d95c5673-4434-4459-85e3-551d040ec4fa.jpg', 2),
  (5, 'Принтер Samsung Xpress SL-M3400ND', 'Монохромный лазерный принтер A4 со скоростью печати до 35 стр/мин. Поддерживает автоматическую двустороннюю печать, подключение по USB и Ethernet. Ресурс картриджа до 5000 страниц. Идеален для малого и среднего офиса.', 18900, 22500, 'SL-M3400ND', TRUE, TRUE, 'https://cdn.poehali.dev/projects/16dea1b8-f4a6-4881-9a41-93285e290dcb/files/7b480da4-bcfe-420d-8269-ca3c4a3d9f8e.jpg', 1),
  (1, 'ККТ АТОЛ 30Ф', 'Компактная онлайн-касса АТОЛ 30Ф с термопечатью и встроенным модулем передачи данных в ОФД. Поддерживает ФФД 1.05, 1.1 и 1.2. Подходит для торговли, услуг, общепита. В комплекте кабель USB и блок питания.', 8990, 10500, 'ATOL-30F', TRUE, TRUE, 'https://cdn.poehali.dev/projects/16dea1b8-f4a6-4881-9a41-93285e290dcb/files/2ab6eab1-153c-4d9b-86e4-e5c56410d4b4.jpg', 1),
  (2, 'Фискальный накопитель ФН-1.1М 15 месяцев', 'ФН-1.1М сроком 15 месяцев. Применяется при сезонной работе, торговле подакцизными товарами или работе на ОСНО. Совместим со всеми сертифицированными ККТ. Поставляется в оригинальной упаковке с голограммой.', 6500, NULL, 'FN-15', TRUE, TRUE, 'https://cdn.poehali.dev/projects/16dea1b8-f4a6-4881-9a41-93285e290dcb/files/79f4245e-3de2-4122-a9e5-333521bfab38.jpg', 1),
  (2, 'Фискальный накопитель ФН-1.1М 36 месяцев', 'ФН-1.1М сроком 36 месяцев. Для ИП и организаций на УСН, ЕСХН, ПСН без торговли подакцизными товарами. Срок 3 года позволяет сократить расходы на замену. Совместим со всеми ККТ. Поставляется с документами.', 9200, NULL, 'FN-36', TRUE, TRUE, 'https://cdn.poehali.dev/projects/16dea1b8-f4a6-4881-9a41-93285e290dcb/files/79f4245e-3de2-4122-a9e5-333521bfab38.jpg', 2),
  (3, 'Код активации ОФД СБИС на 1 год', 'Код активации для подключения ккт к ОФД СБИС (Тензор) на 12 месяцев. Передача данных в ФНС в реальном времени, личный кабинет с отчётностью. Активация в течение 24 часов. Подходит для любой сертифицированной ккт.', 3000, 3500, 'SBIS-OFD-1Y', TRUE, TRUE, 'https://cdn.poehali.dev/projects/16dea1b8-f4a6-4881-9a41-93285e290dcb/files/ff4fb0e7-cf8c-4156-bd34-fad3ef40c673.jpg', 1),
  (3, 'Код активации ОФД Яндекс на 1 год', 'Код активации для подключения ккт к Яндекс ОФД на 12 месяцев. Надёжная передача фискальных данных в ФНС, поддержка 24/7. Совместим со всеми сертифицированными ккт. Активация онлайн без визита в офис.', 3000, 3500, 'YANDEX-OFD-1Y', TRUE, TRUE, 'https://cdn.poehali.dev/projects/16dea1b8-f4a6-4881-9a41-93285e290dcb/files/dc5625ca-48cc-4e6f-a7a4-5fc57c880ab3.jpg', 2);